select IsIntact,RequestID,IsRequest,ResInfo,* from t_PO order by ID desc 



use master  
Drop database [db_RpaZF004]

create database [db_RpaZF004]
use db_RpaZF004

--check sheet
create table t_CS (
	CSID int not null primary key identity,
	CSNO varchar(255) not null unique,
	Supplier varchar(255),
	SupplierCode varchar(255),
	SupplierShortName varchar(255),
	CompanyCode varchar(255),
	SDate date,
	EDate date,
	Price float,
	TaxAmount float,
	PriceIncludingTax float,
	InvoiceStatus  varchar(255),
	Currency  varchar(255),
	ScadaDateTime datetime not null default(getdate()),
	IsScadaFinsh int not null default(0),
	IsIntact int not null default(0),
	RequestID varchar(255),
	IsRequest int not null default(-1),
	ResInfo varchar(max)
)


create table t_PO(
	POID int not null primary key identity,
	CSID int not null foreign key (CSID) references t_CS(CSID),

	--ZFIF001M>>采购订单，采购员描述，订单付款条件，订单付款条件描述，过账日期，采购总价，税率，税额，含税金额  +支付币种
	PONO varchar(255) not null , --②无采购单直接反写主表IsRequest=2，且不再往下采集
	PUser varchar(255),
	PayCode  varchar(255),--①非到付直接反写主表IsRequest=2，且不再往下采集
	PayCodeExplanation varchar(255),
	PostingDate date,
	Price float,
	TaxRate float,
	TaxAmount float,
	PriceIncludingTax float,

	--ME23N>>二级分类 采购组计算Class2
	PGroup varchar(255),

	--ZMMR010>>收款人国家/地区--银行国家代码
	SWIFTCode varchar(255),

	--ZMMF007>>附件
	FilePath varchar(255),

	--计算值>>付款要求完成时间，付款日期说明，二级分类
	PayFinish date,
	PayFinishExplanation varchar(255),
	Class2 varchar(255),	

	--默认值>>付款类型 支付类型 是否有采购订单 对公对私 是否关联资本性支出请购流程 是否基建类 订单齐全
	PurchaseStype varchar(255) not null default('货到付款'),
	PayStype varchar(255) not null default('材料款'),
	IsExistPO varchar(255) not null default('是'),
	BankOf  varchar(255) not null default('对公'),
	IsLinkPR  varchar(255) not null default('否'),
	IsInfrastructure varchar(255) not null default('否'),
	IsOrderComplete varchar(255) not null default('单据齐全')

	--PONO可以重复
)




ALTER TABLE t_PO
ADD CONSTRAINT DF__t_PO__IsOrderCom__32E0915F DEFAULT '单据齐全' FOR IsOrderComplete;


select  * from t_PO order by POID desc

UPDATE t_PO SET IsOrderComplete='单据齐全'


select DISTINCT t_PO.CSID from t_PO left join t_CS  on t_CS.CSID=t_PO.CSID
where IsScadaFinsh=0 and IsRequest<=0 and FilePath is null




select * from t_PO left join t_CS  on t_CS.CSID=t_PO.CSID
where IsScadaFinsh=0 and IsRequest<=0 and FilePath is not null



select DISTINCT t_PO.CSID from t_PO left join t_CS  on t_CS.CSID=t_PO.CSID
where IsIntact=0 and IsRequest<=0 



select * from t_PO left join t_CS  on t_CS.CSID=t_PO.CSID
where IsIntact=0 and IsRequest<=0 


select top 1 PayCode from t_PO where CSID=60 and  PayCode is not null 


select t_PO.POID,t_PO.PayFinish ,t_PO.PUser from t_PO left join t_CS  on t_CS.CSID=t_PO.CSID
where  IsIntact=1 and IsRequest<=0 



select * from t_PO order by ID desc

select * from t_PO left join t_CS  on t_CS.CSID=t_PO.CSID
where IsIntact=1 and IsScadaFinsh=1  and IsRequest<=0 


select IsScadaFinsh,IsIntact,RequestID,IsRequest,ResInfo,* from  t_CS where IsRequest=-1 order by CSID desc



select * from t_PO where CSID IN (select CSID from  t_CS where IsRequest=-1 )


